// src/pages/CreateExperience.js
// صفحة المدرس لإنشاء تجربة سكشن جديدة
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences';
import { coursesService } from '../services/courses';
import { authService } from '../services/auth';

export default function CreateExperience() {
  const navigate = useNavigate();
  const [sections, setSections] = useState([]);
  const [loading, setLoading]   = useState(false);
  const [form, setForm] = useState({
    section         : '',
    title           : '',
    description     : '',
    price           : '0',
    discount_price  : '',
    instructor_cut  : '70',
    college_cut     : '30',
    preview_video_url: '',
    status          : 'draft',
  });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    // جيب كورسات المدرس عشان يختار سكشن
    coursesService.getAll()
      .then(data => {
        const list = data.results ?? data;
        const secs = [];
        list.forEach(c => {
          (c.sections || []).forEach(s => {
            secs.push({ id: s.id, label: `${c.title} › ${s.title}` });
          });
        });
        setSections(secs);
      })
      .catch(console.error);
  }, []);

  const handle = (e) => {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
    // اضبط الـ college cut تلقائي
    if (name === 'instructor_cut') {
      const ic = parseFloat(value) || 0;
      setForm(f => ({ ...f, instructor_cut: value, college_cut: String(100 - ic) }));
    }
  };

  const validate = () => {
    const e = {};
    if (!form.section)    e.section = 'اختر سكشن';
    if (!form.title)      e.title   = 'أدخل عنوان التجربة';
    if (parseFloat(form.price) < 0) e.price = 'السعر لا يمكن أن يكون سالباً';
    const ic = parseFloat(form.instructor_cut);
    const cc = parseFloat(form.college_cut);
    if (ic + cc !== 100)  e.instructor_cut = 'مجموع النسب يجب أن يساوي 100%';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const submit = async (e, publishNow = false) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      const payload = {
        ...form,
        status: publishNow ? 'published' : 'draft',
        discount_price: form.discount_price || null,
      };
      const res = await experiencesService.create(payload);
      alert(publishNow ? '✅ تم النشر!' : '✅ تم الحفظ كمسودة');
      navigate('/experiences');
    } catch (err) {
      const data = err.response?.data;
      if (data && typeof data === 'object') setErrors(data);
      else alert('حدث خطأ أثناء الحفظ');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.container}>
        <h1 style={s.title}>إنشاء تجربة سكشن جديدة 🧪</h1>
        <p style={s.sub}>أضف محتوى مدفوع لسكشن معين يستفيد منه الطلاب الذين فاتهم</p>

        <form style={s.form}>

          {/* Section */}
          <Field label="السكشن" error={errors.section}>
            <select name="section" value={form.section} onChange={handle} style={s.select}>
              <option value="">-- اختر سكشن من كورساتك --</option>
              {sections.map(s => (
                <option key={s.id} value={s.id}>{s.label}</option>
              ))}
            </select>
          </Field>

          {/* Title */}
          <Field label="عنوان التجربة" error={errors.title}>
            <input name="title" value={form.title} onChange={handle}
                   placeholder="مثال: حل تمارين الـ Recursion" style={s.input} />
          </Field>

          {/* Description */}
          <Field label="وصف التجربة">
            <textarea name="description" value={form.description} onChange={handle}
                      placeholder="ماذا سيتعلم الطالب؟" rows={4} style={{...s.input, resize:'vertical'}} />
          </Field>

          {/* Price */}
          <div style={s.row}>
            <Field label="السعر (EGP)" error={errors.price} style={{ flex:1 }}>
              <input type="number" name="price" value={form.price}
                     onChange={handle} min="0" style={s.input} />
            </Field>
            <Field label="السعر بعد الخصم (اختياري)" style={{ flex:1 }}>
              <input type="number" name="discount_price" value={form.discount_price}
                     onChange={handle} min="0" placeholder="اتركه فارغاً لو مفيش خصم"
                     style={s.input} />
            </Field>
          </div>

          {/* Revenue split */}
          <Field label="توزيع الأرباح %" error={errors.instructor_cut}>
            <div style={s.splitWrap}>
              <div style={s.splitItem}>
                <label style={s.splitLabel}>حصة المدرس %</label>
                <input type="number" name="instructor_cut" value={form.instructor_cut}
                       onChange={handle} min="0" max="100" style={s.splitInput} />
              </div>
              <span style={s.splitPlus}>+</span>
              <div style={s.splitItem}>
                <label style={s.splitLabel}>حصة الكلية %</label>
                <input type="number" name="college_cut" value={form.college_cut}
                       readOnly style={{...s.splitInput, opacity:.6}} />
              </div>
              <span style={s.splitEq}>=  100%</span>
            </div>
          </Field>

          {/* Preview URL */}
          <Field label="رابط فيديو Preview مجاني (اختياري)">
            <input name="preview_video_url" value={form.preview_video_url}
                   onChange={handle} placeholder="https://youtube.com/embed/..."
                   style={s.input} />
          </Field>

          {/* Buttons */}
          <div style={s.btnRow}>
            <button type="button" style={s.btnDraft}
                    onClick={(e) => submit(e, false)} disabled={loading}>
              💾 حفظ كمسودة
            </button>
            <button type="button" style={s.btnPublish}
                    onClick={(e) => submit(e, true)} disabled={loading}>
              🚀 نشر الآن
            </button>
          </div>

        </form>
      </div>
    </div>
  );
}

// ── Field wrapper ──────────────────────────────────────────────────────────────
function Field({ label, error, children, style }) {
  return (
    <div style={{ marginBottom: '1.25rem', ...style }}>
      <label style={fs.label}>{label}</label>
      {children}
      {error && <p style={fs.error}>{error}</p>}
    </div>
  );
}

